/** @generated —
 * Template for Dockerfile generation
 * Multi-stage production build with Node 22 alpine
 */

export interface DockerfileOptions {
  entrypoint?: string;
  port?: number;
}

/**
 * Generate production Dockerfile template
 */
export function generateDockerfileTemplate(options: DockerfileOptions): string {
  const { entrypoint = 'dist/packages/execution/src/server.js', port = 3000 } = options;

  return `# syntax=docker/dockerfile:1
# Generated by @flusk/cli

# ── Stage 1: dependencies ──────────────────────────
FROM node:22-alpine AS deps
RUN corepack enable && corepack prepare pnpm@latest --activate
WORKDIR /app
COPY pnpm-lock.yaml pnpm-workspace.yaml package.json ./
COPY packages/*/package.json ./packages/
RUN --mount=type=cache,target=/root/.local/share/pnpm/store \\
    pnpm install --frozen-lockfile --ignore-scripts

# ── Stage 2: build ─────────────────────────────────
FROM deps AS build
COPY . .
RUN pnpm build

# ── Stage 3: runtime ───────────────────────────────
FROM node:22-alpine AS runtime
RUN apk add --no-cache tini && corepack enable
ENV NODE_ENV=production PORT=${port}
WORKDIR /app
COPY --from=build /app/dist ./dist
COPY --from=build /app/node_modules ./node_modules
COPY --from=build /app/package.json ./
COPY docker-entrypoint.sh /usr/local/bin/
RUN chmod +x /usr/local/bin/docker-entrypoint.sh
EXPOSE ${port}
ENTRYPOINT ["tini", "--"]
CMD ["node", "${entrypoint}"]
`;
}
